async function handleAdminLogin(e){e.preventDefault();await hydrateSecurityFromServer();if(isLockedOut()){showLoginError(lockoutMessage());return;}const submitted=adminPasswordInput.value;if(submitted===security.password){security.failCount=0;security.lockedUntil=0;saveSecurityState();localStorage.setItem(ADMIN_SESSION_KEY,"1");adminPasswordInput.value="";adminLoginError.classList.add("hidden");syncAdminUI();return;}security.failCount+=1;if(security.failCount>=MAX_LOGIN_ATTEMPTS){security.lockedUntil=Date.now()+LOCKOUT_MS;security.failCount=0;showLoginError(lockoutMessage());}else{showLoginError(`Mot de passe invalide. Tentatives restantes: ${MAX_LOGIN_ATTEMPTS-security.failCount}.`);}saveSecurityState();}
