async function handleScoreSubmit(e){e.preventDefault();if(!isAdmin())return;const season=normalizeSeasonCode(seasonInput.value);const team=teamSelect.value;const category=categorySelect.value;const tag=canonicalTagName(tagSelect?.value)||DEFAULT_TAGS[0];const score=Number(scoreInput.value);const note=noteInput.value.trim();const occurredAt=normalizeDateTimeInput(occurredAtInput.value);if(!season){showAdminFeedback("Format saison invalide. Utilise LK26, LK27, etc.","error");return;}if(!team||!category||!tag||Number.isNaN(score)||score<0||!occurredAt){showAdminFeedback("Tous les champs de score sont obligatoires.","error");return;}state.entries.unshift({id:createEntryId(),season,team,category,tag,score,note,occurredAt});await persistEntries();if(scoreInput)scoreInput.value="";if(noteInput)noteInput.value="";if(occurredAtInput)occurredAtInput.value=getNowLocalDateTimeValue();if(seasonInput)seasonInput.value=season;refreshAllControls(season);renderAll();showAdminFeedback("Score ajoute.","success");}
function handleTeamAdd(e){e.preventDefault();if(!isAdmin())return;const newName=sanitizeName(teamAddInput.value);if(!newName){showAdminFeedback("Nom de clan invalide.","error");return;}if(hasName(state.teams,newName)){showAdminFeedback("Ce clan existe deja.","error");return;}state.teams.push(newName);state.teamStyles[newName]={color:getDefaultTeamColor(state.teams.length-1),logo:""};teamAddInput.value="";saveState();refreshAllControls(activeSeasonSelect?activeSeasonSelect.value:getCurrentSeasonCode());syncTeamStyleInputs();renderAll();showAdminFeedback("Clan ajoute.","success");}
async function handleTeamRename(e){e.preventDefault();if(!isAdmin())return;const oldName=teamRenameSelect.value;const newName=sanitizeName(teamRenameInput.value);if(!oldName||!newName||normalizeText(oldName)===normalizeText(newName)){showAdminFeedback("Renommage invalide.","error");return;}if(hasName(state.teams,newName)){showAdminFeedback("Un clan avec ce nom existe deja.","error");return;}state.teams=state.teams.map((t)=>t===oldName?newName:t);state.entries=state.entries.map((entry)=>({...entry,team:entry.team===oldName?newName:entry.team}));state.teamStyles[newName]=state.teamStyles[oldName]||{color:getDefaultTeamColor(0),logo:""};delete state.teamStyles[oldName];teamRenameInput.value="";await persistEntries();refreshAllControls(activeSeasonSelect?activeSeasonSelect.value:getCurrentSeasonCode());syncTeamStyleInputs();renderAll();showAdminFeedback("Clan renomme.","success");}
function handleTeamDelete(e){e.preventDefault();if(!isAdmin())return;const target=teamDeleteSelect.value;if(!target){showAdminFeedback("Selectionne un clan a supprimer.","error");return;}if(state.teams.length<=1){showAdminFeedback("Impossible: il faut garder au moins un clan.","error");return;}if(state.entries.some((entry)=>entry.team===target)){showAdminFeedback("Impossible de supprimer ce clan: des scores lui sont associes.","error");return;}state.teams=state.teams.filter((t)=>t!==target);delete state.teamStyles[target];saveState();refreshAllControls(activeSeasonSelect?activeSeasonSelect.value:getCurrentSeasonCode());syncTeamStyleInputs();renderAll();showAdminFeedback("Clan supprime.","success");}
async function handleTeamStyleSave(e){e.preventDefault();if(!isAdmin())return;const team=teamStyleSelect.value;if(!team){showAdminFeedback("Selectionne un clan.","error");return;}const current=getTeamStyle(team);const color=sanitizeHexColor(teamColorInput.value,current.color);let logo=current.logo;const file=teamLogoInput.files?.[0];if(file){if(file.size>MAX_LOGO_FILE_SIZE){showAdminFeedback("Logo trop lourd (max 1.5 MB).","error");return;}try{logo=await readFileAsDataUrl(file);}catch{showAdminFeedback("Impossible de lire le fichier logo.","error");return;}}state.teamStyles[team]={color,logo:logo||""};saveState();teamLogoInput.value="";renderAll();showAdminFeedback("Style du clan mis a jour.","success");}
