function handleCategoryAdd(e){e.preventDefault();if(!isAdmin())return;ensureTaxonomyState();const newName=canonicalCategoryName(categoryAddInput.value);if(!newName){showAdminFeedback("Nom de categorie invalide.","error");return;}if(hasName(state.categories,newName)){showAdminFeedback("Cette categorie existe deja.","error");return;}state.categories.push(newName);categoryAddInput.value="";saveState();refreshAllControls(activeSeasonSelect?activeSeasonSelect.value:getCurrentSeasonCode());renderAll();showAdminFeedback("Categorie ajoutee.","success");}
