function handleCategoryDelete(e){e.preventDefault();if(!isAdmin())return;ensureTaxonomyState();const target=categoryDeleteSelect.value;if(!target){showAdminFeedback("Selectionne une categorie a supprimer.","error");return;}if(state.categories.length<=1){showAdminFeedback("Impossible: il faut garder au moins une categorie.","error");return;}if(state.entries.some((entry)=>entry.category===target)){showAdminFeedback("Impossible de supprimer cette categorie: des scores y sont associes.","error");return;}state.categories=state.categories.filter((c)=>c!==target);saveState();refreshAllControls(activeSeasonSelect?activeSeasonSelect.value:getCurrentSeasonCode());renderAll();showAdminFeedback("Categorie supprimee.","success");}
function handleTagAdd(e){e.preventDefault();if(!isAdmin())return;ensureTaxonomyState();const newName=canonicalTagName(tagAddInput.value);if(!newName){showAdminFeedback("Nom de tag invalide.","error");return;}if(hasName(state.tags,newName)){showAdminFeedback("Ce tag existe deja.","error");return;}state.tags.push(newName);tagAddInput.value="";saveState();refreshAllControls(activeSeasonSelect?activeSeasonSelect.value:getCurrentSeasonCode());renderAll();showAdminFeedback("Tag ajoute.","success");}
async function handleTagRename(e){e.preventDefault();if(!isAdmin())return;ensureTaxonomyState();const oldName=tagRenameSelect.value;const newName=canonicalTagName(tagRenameInput.value);if(!oldName||!newName||normalizeText(oldName)===normalizeText(newName)){showAdminFeedback("Renommage invalide.","error");return;}if(hasName(state.tags,newName)){showAdminFeedback("Un tag avec ce nom existe deja.","error");return;}state.tags=state.tags.map((tag)=>tag===oldName?newName:tag);state.entries=state.entries.map((entry)=>({...entry,tag:entry.tag===oldName?newName:entry.tag}));tagRenameInput.value="";await persistEntries();refreshAllControls(activeSeasonSelect?activeSeasonSelect.value:getCurrentSeasonCode());renderAll();showAdminFeedback("Tag renomme.","success");}
function handleTagDelete(e){e.preventDefault();if(!isAdmin())return;ensureTaxonomyState();const target=tagDeleteSelect.value;if(!target){showAdminFeedback("Selectionne un tag a supprimer.","error");return;}if(state.tags.length<=1){showAdminFeedback("Impossible: il faut garder au moins un tag.","error");return;}if(state.entries.some((entry)=>entry.tag===target)){showAdminFeedback("Impossible de supprimer ce tag: des scores y sont associes.","error");return;}state.tags=state.tags.filter((tag)=>tag!==target);saveState();refreshAllControls(activeSeasonSelect?activeSeasonSelect.value:getCurrentSeasonCode());renderAll();showAdminFeedback("Tag supprime.","success");}
async function handlePasswordChange(e){e.preventDefault();if(!isAdmin())return;await hydrateSecurityFromServer();const currentPassword=currentPasswordInput.value;const newPassword=newPasswordInput.value;const confirmPassword=confirmPasswordInput.value;if(currentPassword!==security.password){showAdminFeedback("Mot de passe actuel incorrect.","error");return;}if(newPassword.length<8){showAdminFeedback("Le nouveau mot de passe doit contenir au moins 8 caracteres.","error");return;}if(newPassword!==confirmPassword){showAdminFeedback("La confirmation du nouveau mot de passe ne correspond pas.","error");return;}security.password=newPassword;security.failCount=0;security.lockedUntil=0;saveSecurityState();const synced=await pushSecurityToServer();passwordChangeForm.reset();showAdminFeedback(synced?"Mot de passe admin mis a jour (global).":"Mot de passe mis a jour localement. Configure /api/admin-password pour le mode global.",synced?"success":"error");}
function syncAdminUI(){if(!hasAdminView)return;const unlocked=isAdmin();adminLocked.classList.toggle("hidden",unlocked);adminUnlocked.classList.toggle("hidden",!unlocked);adminLogout.classList.toggle("hidden",!unlocked);if(unlocked){adminLoginError.classList.add("hidden");adminLockInfo.textContent="Session admin active.";}else{adminPasswordInput.value="";if(isLockedOut()){showLoginError(lockoutMessage());}else{adminLoginError.classList.add("hidden");adminLockInfo.textContent=`5 erreurs consecutives bloquent l'acces 5 minutes. Tentatives restantes: ${Math.max(0,MAX_LOGIN_ATTEMPTS-security.failCount)}.`;}}setupLockoutTicker();}
function setupLockoutTicker(){if(lockTimerId){clearInterval(lockTimerId);lockTimerId=null;}if(!isLockedOut())return;lockTimerId=setInterval(()=>{if(!isLockedOut()){clearInterval(lockTimerId);lockTimerId=null;adminLoginError.classList.add("hidden");adminLockInfo.textContent="Le verrouillage est termine. Tu peux reessayer.";return;}showLoginError(lockoutMessage());},1000);}
function showLoginError(message){if(!adminLoginError||!adminLockInfo)return;adminLoginError.textContent=message;adminLoginError.classList.remove("hidden");adminLockInfo.textContent=message;}
function lockoutMessage(){return `Acces temporairement bloque. Reessaie dans ${Math.max(1,Math.ceil((security.lockedUntil-Date.now())/1000))}s.`;}
function isLockedOut(){return Number(security.lockedUntil||0)>Date.now();}
function isAdmin(){return localStorage.getItem(ADMIN_SESSION_KEY)==="1";}
function refreshAllControls(preferredSeason){refreshSeasonControls(preferredSeason);refreshTeamControls();refreshCategoryControls();refreshTagControls();renderAdminResultsManager();}
function refreshSeasonControls(preferredSeason){const seasons=getSeasonList(state.entries);const previousActive=activeSeasonSelect?activeSeasonSelect.value:"";const previousFilter=filterSeason?filterSeason.value:"";if(seasonsList){seasonsList.innerHTML="";seasons.forEach((season)=>{const option=document.createElement("option");option.value=season;seasonsList.appendChild(option);});}if(activeSeasonSelect){fillSelect(activeSeasonSelect,seasons,{includeAll:true,allLabel:"Toutes"});activeSeasonSelect.value=chooseSelectValue(activeSeasonSelect,[preferredSeason,previousActive,getCurrentSeasonCode(),"all"]);}if(filterSeason){fillSelect(filterSeason,seasons,{includeAll:true,allLabel:"Toutes"});filterSeason.value=chooseSelectValue(filterSeason,[preferredSeason,previousFilter,"all"]);}if(seasonInput&&!seasonInput.value)seasonInput.value=getCurrentSeasonCode();}
function refreshTeamControls(){fillSelect(teamSelect,state.teams);fillSelect(teamRenameSelect,state.teams);fillSelect(teamDeleteSelect,state.teams);fillSelect(teamStyleSelect,state.teams);fillSelect(filterTeam,state.teams,{includeAll:true,allLabel:"Tous"});syncTeamStyleInputs();}
function refreshCategoryControls(){ensureTaxonomyState();const ordered=getOrderedCategories();fillCategorySelect(categorySelect,ordered);fillCategorySelect(categoryRenameSelect,ordered);fillCategorySelect(categoryDeleteSelect,ordered);fillCategorySelect(activeCategorySelect,ordered,{includeAll:true,allLabel:"Toutes"});fillCategorySelect(filterCategory,ordered,{includeAll:true,allLabel:"Toutes"});}
